import React, { useState, useRef } from 'react';
import axios from 'axios';

const API_URL = 'http://localhost:5000/api';

function App() {
    const [token, setToken] = useState(localStorage.getItem('token'));
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [isLogin, setIsLogin] = useState(true);
    const [scanEmail, setScanEmail] = useState('');
    const [scanResult, setScanResult] = useState(null);
    const [adText, setAdText] = useState('');
    const [adResult, setAdResult] = useState(null);
    const [loading, setLoading] = useState(false);
    const [copied, setCopied] = useState(false);
    const reportRef = useRef(null);

    // Handle Authentication
    const handleAuth = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const endpoint = isLogin ? '/auth/login' : '/auth/register';
            const response = await axios.post(`${API_URL}${endpoint}`, { email, password });
            localStorage.setItem('token', response.data.token);
            setToken(response.data.token);
            alert(response.data.message);
        } catch (error) {
            alert(error.response?.data?.error || 'Authentication failed');
        }
        setLoading(false);
    };

    // Handle Email Scan
    const handleEmailScan = async () => {
        if (!scanEmail) {
            alert('Please enter an email');
            return;
        }
        setLoading(true);
        try {
            const response = await axios.post(`${API_URL}/scan/email`, { email: scanEmail }, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setScanResult(response.data);
        } catch (error) {
            alert('Scan failed: ' + (error.response?.data?.error || 'Unknown error'));
        }
        setLoading(false);
    };

    // Handle Ad Analysis
    const handleAdAnalysis = async () => {
        if (!adText) {
            alert('Please enter ad text');
            return;
        }
        setLoading(true);
        try {
            const response = await axios.post(`${API_URL}/scan/ad`, { adText }, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setAdResult(response.data);
        } catch (error) {
            alert('Analysis failed');
        }
        setLoading(false);
    };

    // Handle Logout
    const handleLogout = () => {
        localStorage.removeItem('token');
        setToken(null);
        setScanResult(null);
        setAdResult(null);
    };

    // ========== NEW FEATURE 1: COPY TO CLIPBOARD ==========
    const copyToClipboard = async (text, type) => {
        try {
            await navigator.clipboard.writeText(text);
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
            alert(`${type} copied to clipboard!`);
        } catch (err) {
            alert('Failed to copy');
        }
    };

    // ========== NEW FEATURE 2: DOWNLOAD PDF REPORT ==========
    const downloadPDFReport = () => {
        const reportContent = generateReportHTML();
        
        // Create a blob and download
        const blob = new Blob([reportContent], { type: 'text/html' });
        const link = document.createElement('a');
        const url = URL.createObjectURL(blob);
        link.href = url;
        link.download = `beware_report_${new Date().toISOString().slice(0, 19)}.html`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
    };

    const generateReportHTML = () => {
        return `<!DOCTYPE html>
        <html>
        <head>
            <title>BeWare Privacy Report</title>
            <style>
                * { margin: 0; padding: 0; box-sizing: border-box; }
                body {
                    font-family: 'Segoe UI', Arial, sans-serif;
                    background: #0a0a0f;
                    color: #e0e0e0;
                    padding: 40px;
                    line-height: 1.6;
                }
                .container {
                    max-width: 800px;
                    margin: 0 auto;
                    background: #13131a;
                    border: 1px solid #2a2a35;
                    border-radius: 16px;
                    padding: 32px;
                }
                .header {
                    text-align: center;
                    border-bottom: 2px solid #1a5cff;
                    padding-bottom: 20px;
                    margin-bottom: 30px;
                }
                .logo { font-size: 48px; margin-bottom: 10px; }
                h1 { color: white; font-size: 28px; }
                .date { color: #888; font-size: 12px; margin-top: 10px; }
                .section {
                    margin-bottom: 30px;
                    padding: 20px;
                    background: #0f0f12;
                    border-radius: 12px;
                    border-left: 3px solid #1a5cff;
                }
                .section h2 { color: #1a5cff; margin-bottom: 15px; font-size: 18px; }
                .risk-meter {
                    text-align: center;
                    padding: 20px;
                    background: #1a1a22;
                    border-radius: 12px;
                    margin: 20px 0;
                }
                .risk-score {
                    font-size: 48px;
                    font-weight: bold;
                    margin: 10px 0;
                }
                .risk-low { color: #4ade80; }
                .risk-medium { color: #fbbf24; }
                .risk-high { color: #f87171; }
                .progress-bar {
                    width: 100%;
                    height: 12px;
                    background: #2a2a35;
                    border-radius: 10px;
                    overflow: hidden;
                    margin: 15px 0;
                }
                .progress-fill {
                    height: 100%;
                    transition: width 0.5s;
                    border-radius: 10px;
                }
                .badge {
                    display: inline-block;
                    padding: 4px 12px;
                    border-radius: 20px;
                    font-size: 12px;
                    margin: 5px;
                }
                .badge-danger { background: #7f1a1a; color: #fecaca; }
                .badge-warning { background: #78350f; color: #fed7aa; }
                .badge-success { background: #064e3b; color: #a7f3d0; }
                .footer {
                    text-align: center;
                    padding-top: 20px;
                    border-top: 1px solid #2a2a35;
                    margin-top: 20px;
                    font-size: 12px;
                    color: #666;
                }
            </style>
        </head>
        <body>
            <div class="container">
                <div class="header">
                    <div class="logo">🛡️</div>
                    <h1>BeWare Privacy Report</h1>
                    <div class="date">Generated: ${new Date().toLocaleString()}</div>
                </div>
                
                ${generateEmailSection()}
                ${generateAdSection()}
                
                <div class="footer">
                    <p>BeWare - Digital Privacy Auditor</p>
                    <p>This report is for informational purposes only.</p>
                </div>
            </div>
        </body>
        </html>`;
    };

    const generateEmailSection = () => {
        if (!scanResult) return '';
        const riskColor = scanResult.riskScore >= 60 ? 'risk-high' : (scanResult.riskScore >= 30 ? 'risk-medium' : 'risk-low');
        return `
        <div class="section">
            <h2>📧 Email Breach Analysis</h2>
            <p><strong>Email Scanned:</strong> ${scanResult.email}</p>
            <div class="risk-meter">
                <div>Risk Score</div>
                <div class="risk-score ${riskColor}">${scanResult.riskScore}%</div>
                <div class="progress-bar">
                    <div class="progress-fill" style="width: ${scanResult.riskScore}%; background: ${scanResult.riskScore >= 60 ? '#f87171' : (scanResult.riskScore >= 30 ? '#fbbf24' : '#4ade80')}"></div>
                </div>
                <div><span class="badge ${scanResult.breachCount === 0 ? 'badge-success' : 'badge-danger'}">${scanResult.breachCount === 0 ? '✅ No Breaches Found' : `⚠️ ${scanResult.breachCount} Breach(es) Found`}</span></div>
            </div>
            ${scanResult.breaches?.length > 0 ? `
            <div style="margin-top: 15px;">
                <strong>Breach Details:</strong>
                <ul style="margin-top: 10px; list-style: none;">
                    ${scanResult.breaches.map(b => `<li style="padding: 8px; margin: 5px 0; background: #1a1a22; border-radius: 8px;">📌 <strong>${b.Name}</strong> - ${b.BreachDate}<br><span style="font-size: 12px; color: #888;">${b.PwnCount} accounts affected</span></li>`).join('')}
                </ul>
            </div>
            ` : '<p style="margin-top: 15px;">✅ Good news! No data breaches found for this email.</p>'}
        </div>`;
    };

    const generateAdSection = () => {
        if (!adResult) return '';
        return `
        <div class="section">
            <h2>🎯 Ad Manipulation Analysis</h2>
            <div class="risk-meter">
                <div>Manipulation Score</div>
                <div class="risk-score ${adResult.manipulationScore >= 60 ? 'risk-high' : (adResult.manipulationScore >= 30 ? 'risk-medium' : 'risk-low')}">${adResult.manipulationScore}%</div>
                <div class="progress-bar">
                    <div class="progress-fill" style="width: ${adResult.manipulationScore}%; background: ${adResult.manipulationScore >= 60 ? '#f87171' : (adResult.manipulationScore >= 30 ? '#fbbf24' : '#4ade80')}"></div>
                </div>
                <div><span class="badge ${adResult.urgencyLevel === 'High' ? 'badge-danger' : (adResult.urgencyLevel === 'Medium' ? 'badge-warning' : 'badge-success')}">Urgency: ${adResult.urgencyLevel}</span></div>
            </div>
            ${adResult.detectedTactics?.length > 0 ? `
            <div style="margin-top: 15px;">
                <strong>Detected Manipulation Tactics:</strong>
                <ul style="margin-top: 10px; list-style: none;">
                    ${adResult.detectedTactics.map(t => `<li style="padding: 8px; margin: 5px 0; background: #1a1a22; border-radius: 8px;">${t.icon || '🎯'} <strong>${t.name}</strong> - Impact: +${t.weight}%<br><span style="font-size: 12px; color: #888;">${t.description || 'Psychological manipulation technique'}</span></li>`).join('')}
                </ul>
            </div>
            ` : '<p>No manipulation tactics detected.</p>'}
        </div>`;
    };

    // ========== NEW FEATURE 3: RISK METER COMPONENT ==========
    const RiskMeter = ({ score, label, type }) => {
        const getColor = () => {
            if (score >= 60) return { bg: '#f87171', text: '#f87171', label: 'High Risk' };
            if (score >= 30) return { bg: '#fbbf24', text: '#fbbf24', label: 'Medium Risk' };
            return { bg: '#4ade80', text: '#4ade80', label: 'Low Risk' };
        };
        
        const color = getColor();
        const angle = -90 + (score / 100) * 180;
        
        return (
            <div style={{ textAlign: 'center', padding: '16px', background: '#1a1a22', borderRadius: '12px' }}>
                <p style={{ color: '#888', fontSize: '12px', marginBottom: '8px' }}>{label}</p>
                <div style={{ position: 'relative', width: '120px', height: '60px', margin: '0 auto' }}>
                    <svg width="120" height="60" viewBox="0 0 120 60">
                        <path d="M 10 50 A 50 50 0 0 1 110 50" fill="none" stroke="#2a2a35" strokeWidth="8" strokeLinecap="round"/>
                        <path d="M 10 50 A 50 50 0 0 1 110 50" fill="none" stroke={color.bg} strokeWidth="8" strokeLinecap="round" strokeDasharray={`${(score / 100) * 157} 157`} style={{ transition: 'stroke-dasharray 0.5s' }}/>
                        <g transform={`rotate(${angle} 60 50)`}>
                            <line x1="60" y1="50" x2="60" y2="20" stroke="#e0e0e0" strokeWidth="2" strokeLinecap="round"/>
                            <circle cx="60" cy="50" r="5" fill={color.bg}/>
                        </g>
                    </svg>
                    <div style={{ position: 'absolute', bottom: '-5px', left: '50%', transform: 'translateX(-50%)', textAlign: 'center' }}>
                        <span style={{ fontSize: '20px', fontWeight: 'bold', color: color.text }}>{score}</span>
                        <span style={{ fontSize: '12px', color: '#888' }}>%</span>
                    </div>
                </div>
                <p style={{ fontSize: '11px', marginTop: '12px', color: color.text }}>{color.label}</p>
            </div>
        );
    };

    // Login/Register Screen
    if (!token) {
        return (
            <div style={styles.authContainer}>
                <div style={styles.authCard}>
                    <div style={styles.logo}>
                        <span style={styles.logoIcon}>🛡️</span>
                        <h1 style={styles.logoText}>BeWare</h1>
                        <p style={styles.logoSubtext}>Digital Privacy Auditor</p>
                    </div>
                    
                    <form onSubmit={handleAuth}>
                        <input
                            type="email"
                            placeholder="Email"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            style={styles.input}
                            required
                        />
                        <input
                            type="password"
                            placeholder="Password"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            style={styles.input}
                            required
                        />
                        <button type="submit" disabled={loading} style={styles.button}>
                            {loading ? 'Loading...' : (isLogin ? 'Login' : 'Create Account')}
                        </button>
                    </form>
                    
                    <p style={styles.switchText}>
                        {isLogin ? "Don't have an account? " : "Already have an account? "}
                        <button onClick={() => setIsLogin(!isLogin)} style={styles.switchButton}>
                            {isLogin ? 'Register' : 'Login'}
                        </button>
                    </p>
                </div>
            </div>
        );
    }

    // Dashboard
    return (
        <div style={styles.dashboard}>
            {/* Header */}
            <header style={styles.header}>
                <h1 style={styles.headerTitle}>🛡️ BeWare</h1>
                <button onClick={handleLogout} style={styles.logoutBtn}>Logout</button>
            </header>
            
            {/* Main Content */}
            <main style={styles.main}>
                <h2 style={styles.pageTitle}>Privacy Dashboard</h2>
                
                {/* Email Scanner Card with Risk Meter */}
                <div style={styles.card}>
                    <h3 style={styles.cardTitle}>📧 Email Breach Scanner</h3>
                    <div style={styles.inputGroup}>
                        <input
                            type="email"
                            value={scanEmail}
                            onChange={(e) => setScanEmail(e.target.value)}
                            placeholder="Enter your email address"
                            style={styles.input}
                        />
                        <button onClick={handleEmailScan} disabled={loading} style={styles.buttonSmall}>
                            {loading ? 'Scanning...' : 'Scan'}
                        </button>
                    </div>
                    
                    {scanResult && (
                        <div style={styles.resultBox}>
                            {/* NEW: Risk Meter */}
                            <div style={{ marginBottom: '20px' }}>
                                <RiskMeter score={scanResult.riskScore} label="PRIVACY RISK SCORE" type="email" />
                            </div>
                            
                            <p style={scanResult.breachCount > 0 ? styles.resultDanger : styles.resultSuccess}>
                                {scanResult.breachCount > 0 
                                    ? `⚠️ Found in ${scanResult.breachCount} breach(es)` 
                                    : '✅ No breaches found'}
                            </p>
                            
                            {/* NEW: Copy to Clipboard Button */}
                            <div style={{ display: 'flex', gap: '10px', marginTop: '10px', marginBottom: '15px' }}>
                                <button 
                                    onClick={() => copyToClipboard(
                                        `Email: ${scanResult.email}\nBreaches Found: ${scanResult.breachCount}\nRisk Score: ${scanResult.riskScore}%\n${scanResult.breaches?.map(b => `- ${b.Name} (${b.BreachDate})`).join('\n') || 'No breaches found'}`,
                                        'Breach Report'
                                    )}
                                    style={styles.copyBtn}
                                >
                                    📋 {copied ? 'Copied!' : 'Copy Report'}
                                </button>
                            </div>
                            
                            {scanResult.breaches?.length > 0 && (
                                <div style={styles.breachList}>
                                    {scanResult.breaches.map((b, i) => (
                                        <div key={i} style={styles.breachItem}>
                                            <strong>{b.Name}</strong>
                                            <span style={styles.breachDate}>{b.BreachDate}</span>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    )}
                </div>
                
                {/* Ad Analyzer Card with Risk Meter */}
                <div style={styles.card}>
                    <h3 style={styles.cardTitle}>🎯 Ad Manipulation Detector</h3>
                    <textarea
                        value={adText}
                        onChange={(e) => setAdText(e.target.value)}
                        placeholder="Paste advertisement text here...&#10;&#10;Example: 'Limited time offer! Only 2 left in stock!'"
                        rows="4"
                        style={styles.textarea}
                    />
                    <button onClick={handleAdAnalysis} disabled={loading} style={styles.buttonFull}>
                        {loading ? 'Analyzing...' : 'Analyze Ad'}
                    </button>
                    
                    {adResult && (
                        <div style={styles.resultBox}>
                            {/* NEW: Risk Meter for Ad Manipulation */}
                            <div style={{ marginBottom: '20px' }}>
                                <RiskMeter score={adResult.manipulationScore} label="MANIPULATION SCORE" type="ad" />
                            </div>
                            
                            <p>Urgency Level: <strong style={{ color: adResult.urgencyLevel === 'High' ? '#f87171' : (adResult.urgencyLevel === 'Medium' ? '#fbbf24' : '#4ade80') }}>
                                {adResult.urgencyLevel}
                            </strong></p>
                            
                            {adResult.detectedTactics?.length > 0 && (
                                <div style={styles.tacticList}>
                                    <p style={styles.tacticTitle}>Detected Tactics:</p>
                                    {adResult.detectedTactics.map((t, i) => (
                                        <div key={i} style={styles.tacticItem}>
                                            <span>{t.icon || '🎯'}</span>
                                            <strong>{t.name}</strong>
                                            <span style={{ color: '#888' }}>+{t.weight}%</span>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    )}
                </div>
                
                {/* NEW: Download Report Button - Shows when either scan is done */}
                {(scanResult || adResult) && (
                    <div style={{ ...styles.card, background: '#1a5cff20', borderColor: '#1a5cff', textAlign: 'center' }}>
                        <h3 style={{ ...styles.cardTitle, color: '#1a5cff' }}>📄 Export Privacy Report</h3>
                        <p style={{ color: '#888', fontSize: '14px', marginBottom: '16px' }}>
                            Download a complete report of all scans and analyses
                        </p>
                        <button onClick={downloadPDFReport} style={styles.downloadBtn}>
                            📥 Download PDF Report
                        </button>
                    </div>
                )}
            </main>
        </div>
    );
}

